// Обработка smartgym/<deviceId>/status: обновление devices и theft alert.
function weekStartMs() {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    d.setDate(diff);
    return d.getTime();
}

const topic = msg.topic || '';
const parts = topic.split('/');
if (parts.length < 3 || parts[0] !== 'smartgym') {
    return null;
}
const deviceId = parts[1];

let payload;
try {
    const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : msg.payload;
    if (typeof raw === 'string') {
        const t = raw.trim();
        if (t.startsWith('{')) {
            payload = JSON.parse(t);
        } else {
            // Поддержка простого текстового статуса: "online"/"offline"/"workshift".
            payload = { status: t };
        }
    } else {
        payload = raw;
    }
} catch (e) {
    node.warn('status JSON parse error: ' + e.message);
    return null;
}

const status = payload.status;
if (!status) return null;

const devices = global.get('devices') || {};
const alerts = global.get('alerts') || [];
const prev = devices[deviceId] || {};
const now = Date.now();
const weekStart = weekStartMs();
const userId = payload.user_id || prev.user_id || null;

// Новая сессия workshift — инкремент sessions у пользователя.
if (status === 'workshift' && prev.status !== 'workshift' && userId) {
    const users = global.get('users') || {};
    const u = users[userId] || {
        total_reps: 0,
        points: 0,
        sessions: 0,
        sessions_this_week: 0,
        week_start: weekStart,
        last_rep_at: 0
    };
    if (u.week_start !== weekStart) {
        u.sessions_this_week = 0;
        u.week_start = weekStart;
    }
    u.sessions += 1;
    u.sessions_this_week += 1;
    users[userId] = u;
    global.set('users', users);
}

const endedWorkshift = prev.status === 'workshift' && status === 'online';

const next = {
    deviceId,
    status,
    user_id: status === 'workshift' ? userId : (prev.user_id || null),
    on_dock: prev.on_dock === true,
    idle_since: prev.idle_since || 0,
    last_seen: now,
    updated_at: new Date(now).toISOString(),
    had_session: prev.had_session || status === 'workshift' || (prev.reps_in_session || 0) > 0,
    last_workshift_end: endedWorkshift ? now : (prev.last_workshift_end || 0),
    last_rep_at: prev.last_rep_at || 0,
    reps_in_session: status === 'workshift'
        ? (prev.status === 'workshift' ? (prev.reps_in_session || 0) : 0)
        : 0
};

devices[deviceId] = next;
global.set('devices', devices);

let alertsChanged = false;
let updatedAlerts = [...alerts];

if (status === 'offline') {
    updatedAlerts = updatedAlerts.filter(
        a => !(a.type === 'theft_alert' && a.deviceId === deviceId && a.active)
    );
    updatedAlerts.unshift({
        type: 'theft_alert',
        deviceId,
        message: 'ТРЕВОГА: ' + deviceId + ' offline (возможная кража)',
        timestamp: now,
        active: true
    });
    alertsChanged = true;
} else {
    updatedAlerts = updatedAlerts.map(a => {
        if (a.type === 'theft_alert' && a.deviceId === deviceId && a.active) {
            alertsChanged = true;
            return { ...a, active: false, cleared_at: now };
        }
        return a;
    });
}

if (alertsChanged) {
    global.set('alerts', updatedAlerts.slice(0, 20));
}

msg.deviceId = deviceId;
msg.status = status;
msg.refresh = true;

// Второй выход — popup на Dashboard 2.0 при событии кражи (offline/LWT).
const theftNotify = status === 'offline'
    ? {
        payload: 'ТРЕВОГА: ' + deviceId + ' offline (возможная кража)',
        show: true,
        ui_update: {
            color: 'red',
            displayTime: 15,
            position: 'center center',
            allowDismiss: true,
            dismissText: 'OK',
            showCountdown: true
        }
    }
    : null;

return [msg, theftNotify];

// Обработка lift_rep: привязка к user_id из активной сессии устройства.
const topic = msg.topic || '';
const parts = topic.split('/');
if (parts.length < 3 || parts[0] !== 'smartgym') {
    return null;
}
const deviceId = parts[1];

let payload;
try {
    const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : msg.payload;
    if (typeof raw === 'string') {
        payload = JSON.parse(raw.trim());
    } else {
        payload = raw;
    }
} catch (e) {
    node.warn('exercise JSON parse error: ' + e.message);
    return null;
}

if (!payload || payload.event !== 'lift_rep') {
    return null;
}

const devices = global.get('devices') || {};
const device = devices[deviceId] || {};
const userId = device.user_id;

if (!userId) {
    node.warn('lift_rep без активного user_id для ' + deviceId);
    return null;
}

const repDelta = Number(payload.rep_delta) || 1;
const POINTS_PER_REP = 10;
const now = Date.now();

function weekStartMs() {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    const day = d.getDay();
    const diff = d.getDate() - day + (day === 0 ? -6 : 1);
    d.setDate(diff);
    return d.getTime();
}

const users = global.get('users') || {};
const weekStart = weekStartMs();
const u = users[userId] || {
    total_reps: 0,
    points: 0,
    sessions: 0,
    sessions_this_week: 0,
    week_start: weekStart,
    last_rep_at: 0
};

if (u.week_start !== weekStart) {
    u.sessions_this_week = 0;
    u.week_start = weekStart;
}

u.total_reps += repDelta;
u.points += repDelta * POINTS_PER_REP;
u.last_rep_at = now;
users[userId] = u;
global.set('users', users);

devices[deviceId] = {
    ...device,
    had_session: true,
    last_rep_at: now,
    reps_in_session: (device.reps_in_session || 0) + repDelta
};
global.set('devices', devices);

msg.deviceId = deviceId;
msg.userId = userId;
msg.repDelta = repDelta;
msg.refresh = true;
return msg;

// Обработка smartgym/<deviceId>/dock: состояние «гантель на стойке».
const topic = msg.topic || '';
const parts = topic.split('/');
if (parts.length < 3 || parts[0] !== 'smartgym' || parts[2] !== 'dock') {
    return null;
}
const deviceId = parts[1];

let payload;
try {
    const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : msg.payload;
    payload = typeof raw === 'string' ? JSON.parse(raw.trim()) : raw;
} catch (e) {
    node.warn('dock JSON parse error: ' + e.message);
    return null;
}

if (payload.on_dock === undefined) {
    return null;
}

const onDock = payload.on_dock === true || payload.on_dock === 'true';
const devices = global.get('devices') || {};
const prev = devices[deviceId] || {};
const now = Date.now();

devices[deviceId] = {
    ...prev,
    deviceId,
    on_dock: onDock,
    dock_updated_at: new Date(now).toISOString(),
    last_seen: now
};
global.set('devices', devices);

msg.deviceId = deviceId;
msg.on_dock = onDock;
msg.refresh = true;
return msg;

// idle_reminder: online + on_dock=false + прошло IDLE_MS с начала этого состояния.
// Снимается, если хотя бы одно условие перестало выполняться.
const IDLE_MS = 10 * 1000;
const now = Date.now();
const devices = global.get('devices') || {};
const alerts = global.get('alerts') || [];
let changed = false;
let updated = [...alerts];

for (const deviceId of Object.keys(devices)) {
    const d = devices[deviceId];
    const online = d.status === 'online';
    const onDock = d.on_dock === true;

    if (online && !onDock) {
        if (!d.idle_since) {
            d.idle_since = now;
        }
    } else {
        d.idle_since = 0;
    }
    devices[deviceId] = d;

    const shouldAlert = online && !onDock && d.idle_since && (now - d.idle_since >= IDLE_MS);
    const idx = updated.findIndex(
        a => a.type === 'idle_reminder' && a.deviceId === deviceId && a.active
    );

    if (shouldAlert && idx === -1) {
        updated.unshift({
            type: 'idle_reminder',
            deviceId,
            message: 'Напоминание: уберите гантель ' + deviceId + ' на место',
            timestamp: now,
            active: true
        });
        changed = true;
    } else if (!shouldAlert && idx !== -1) {
        updated[idx] = { ...updated[idx], active: false, cleared_at: now };
        changed = true;
    }
}

global.set('devices', devices);
if (changed) {
    global.set('alerts', updated.slice(0, 20));
}

msg.refresh = true;
return msg;

// Формирование payload для Dashboard 2.0 из global context.
const devices = global.get('devices') || {};
const users = global.get('users') || {};
const alerts = global.get('alerts') || [];

const deviceRows = Object.values(devices).map(d => ({
    'Устройство': d.deviceId,
    'Статус': d.status,
    'На месте': d.on_dock ? 'да' : 'нет',
    'Пользователь': d.user_id || '-',
    'Обновлено': d.updated_at || '-'
}));

const leaderRows = Object.entries(users)
    .map(([id, u]) => ({
        'Пользователь': id,
        'Очки': u.points || 0,
        'Повторения': u.total_reps || 0,
        'Сессии': u.sessions || 0,
        'Активный': (u.sessions_this_week || 0) >= 3 ? 'да' : 'нет'
    }))
    .sort((a, b) => b['Очки'] - a['Очки']);

const activeAlerts = alerts.filter(a => a.active);
const alertRows = activeAlerts.map(a => ({
    'Тип': a.type,
    'Устройство': a.deviceId || '-',
    'Сообщение': a.message,
    'Время': new Date(a.timestamp).toLocaleTimeString()
}));

const totalReps = Object.values(users).reduce((s, u) => s + (u.total_reps || 0), 0);
const totalSessions = Object.values(users).reduce((s, u) => s + (u.sessions || 0), 0);
const uniqueUsers = Object.keys(users).length;
const avgRepsPerSession = totalSessions > 0
    ? Math.round((totalReps / totalSessions) * 10) / 10
    : 0;

const statsRows = [
    { 'Метрика': 'Всего повторений', 'Значение': totalReps },
    { 'Метрика': 'Количество сессий', 'Значение': totalSessions },
    { 'Метрика': 'Уникальных пользователей', 'Значение': uniqueUsers },
    { 'Метрика': 'Среднее повторений на сессию', 'Значение': avgRepsPerSession }
];

const deviceList = Object.values(devices);
const totalDevices = deviceList.length;
const busyDevices = deviceList.filter(d => d.status === 'workshift').length;
const occupiedPct = totalDevices > 0
    ? Math.round((busyDevices / totalDevices) * 100)
    : 0;

return [
    { payload: deviceRows },
    { payload: leaderRows },
    { payload: alertRows },
    { payload: statsRows },
    {
        payload: occupiedPct,
        ui_update: {
            label: 'Занятость: ' + busyDevices + '/' + totalDevices
        }
    }
];
